function LxCopyrightCtrl:Initialize()
    LxBaseCtrl.Initialize(self)

    self._holiday = {}
end

function LxCopyrightCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end

function LxCopyrightCtrl:SetHolidays(dataList)
    if not dataList then
        dataList = STATIC_HOLIDAY
    end
    local holiday = {}
    for k,v in ipairs(dataList) do
        holiday[v] = true
    end
    self._holiday = holiday
end

function LxCopyrightCtrl:SetBirth(birthdayStr)
    self._birthDataStr = birthdayStr
    self._realNameAge = 0
    local tbl = string.split(birthdayStr, "-") or {}
    if tbl and #tbl >= 3 then
        self._birthData = {
            year = tonumber(tbl[1]) or 0,
            month = tonumber(tbl[2]) or 0,
            day = tonumber(tbl[3]) or 0,
        }
        self:UpdateRealName()
        LxPlayerPrefs.sdkAge = self._realNameAge
    else
        LxPlayerPrefs.sdkAge = 0
        self._birthData = nil
    end
end

function LxCopyrightCtrl:UpdateRealName()
    local age = 0
    if self._birthData then
        local sDate = LxUtil.OSDate("*t", LxUtil.OSTime())
        local year, month, day = sDate.year, sDate.month, sDate.day
        age = year - self._birthData.year
        if self._birthData.month > month then
            age = age - 1
        elseif self._birthData.month == month and self._birthData.day > day then
            age = age - 1
        end
        if age < 0 then
            age = 0
        end
    end
    self._realNameAge = age
    if LOG_INFO_ENABLED then
        printInfo("copyright", "real age = "..tostring(age))
    end
end

function LxCopyrightCtrl:SetIdCard(idCard)
    self._idCard = idCard
end

function LxCopyrightCtrl:SetIsRealName(bReal)
    self._isRealName = bReal
end

function LxCopyrightCtrl:ResetDefault()
    self:SetBirth("")
    self:SetIdCard("")
    self:SetIsRealName(false)
end

function LxCopyrightCtrl:DoReqHolidayDataList(callback)
    local url = gLxServerList.liberty_date_url
    if string.isempty(url) then
        self:SetHolidays(nil)
        callback(false)
        return
    end
    local urlList = {url}
    MgrCenter.HttpMgr:DoGet(urlList, function(httpUrl, isOk, data)
        if not isOk or data == "null" then
            self:SetHolidays(nil)
            callback(false)
            return
        end
        local dataList = CJSON.decode(data)
        self:SetHolidays(dataList)
        callback(true)
    end, true)

end

function LxCopyrightCtrl:DoReqRealName(userName, name, id, callback)
    local client_secret = "uou8xohag4uq438w63j1fm0ga4lthx43zz27fo"
    local originStr = string.format("idCard=%s&name=%s&userName=%s&secret=%s",id, name, userName, client_secret)
    local sign = PJXUtil.md5(originStr)

    local uri = "/client/userinfo/verify?"..string.format("userName=%s&name=%s&idCard=%s&sign=%s",userName,name, id, sign)
    local urlList = { LxGameSettings.url1 .. uri, LxGameSettings.url2 .. uri}
    local idx = self._reqRealNameIdx or 0
    idx = idx + 1
    self._reqRealNameIdx = idx
    MgrCenter.HttpMgr:DoPost(urlList, function(httpUrl, isOk, data)
        if idx ~= self._reqRealNameIdx then
            if LOG_INFO_ENABLED then
                printError("auth", "realname idx not match! url="..httpUrl)
            end
            return
        end
        if not isOk then
            if LOG_INFO_ENABLED then
                printError("auth", "realname error! url="..httpUrl)
            end
            callback(false)
            return
        end
        if data == "null" then
            callback(false)
            return
        end
        local result = CJSON.decode(data)
        if result.code ~= 0 then
            if LOG_ERROR_ENABLED then
                LogError(string.format("auth realname error, code:%s, message:%s \n url:%s", tostring(result.code) ,tostring(result.msg), httpUrl))
            end
            callback(false)
            return
        end
        callback(true, result)
    end, true)

end

function LxCopyrightCtrl:DoRegisterUserInfo(name, pwd, callback)
    local uri = "/client/register?"..string.format("userName=%s&password=%s",tostring(name),tostring(pwd))
    local urlList = { LxGameSettings.url1 .. uri, LxGameSettings.url2 .. uri}
    local idx = self._reqRegisterIdx or 0
    idx = idx + 1
    self._reqRegisterIdx = idx
    MgrCenter.HttpMgr:DoPost(urlList, function(httpUrl, isOk, data)
        if idx ~= self._reqRegisterIdx then
            if LOG_INFO_ENABLED then
                printError("auth", "registerinfo idx not match! url="..httpUrl)
            end
            return
        end
        if not isOk then
            if LOG_INFO_ENABLED then
                printError("auth", "registerinfo error! url="..httpUrl)
            end
            callback(false)
            return
        end
        if data == "null" then
            callback(false)
            return
        end
        local result = CJSON.decode(data)
        callback(true, result)
    end)
end

function LxCopyrightCtrl:DoGetUserInfo(name, pwd,callback)
    local uri = "/client/getuserinfo?"..string.format("userName=%s&password=%s",tostring(name),tostring(pwd))
    local urlList = { LxGameSettings.url1 .. uri, LxGameSettings.url2 .. uri}
    local idx = self._reqUserIdx or 0
    idx = idx + 1
    self._reqUserIdx = idx
    LxPlayerPrefs.sdkUser = name
    LxPlayerPrefs.sdkToken = ""

    MgrCenter.HttpMgr:DoPost(urlList, function(httpUrl, isOk, data)
        if idx ~= self._reqUserIdx then
            if LOG_INFO_ENABLED then
                printError("auth", "getuserinfo idx not match! url="..httpUrl)
            end
            return
        end
        if not isOk then
            if LOG_INFO_ENABLED then
                printError("auth", "getuserinfo error! url="..httpUrl)
            end
            callback(false)
            return
        end
        if data == "null" then
            callback(false)
            return
        end
        if LOG_INFO_ENABLED then
            printInfo("auth", "")
        end
        local result = CJSON.decode(data)
        if result.code ~= 0 then
            if LOG_ERROR_ENABLED then
                LogError(string.format("auth getuserinfo error, code:%s, message:%s \n url:%s", tostring(result.code) ,tostring(result.msg), httpUrl))
            end
            callback(false)
            return
        end

        local resultData = result.data
        resultData.userName = name
        LxPlayerPrefs.sdkToken = pwd
        gLxSdkImpl:CallMethod(SdkMethod.OnLoginResult, true , resultData)
        callback(resultData)
    end)
end

function LxCopyrightCtrl:GetAgeRechargeLimit(age)
    if age < 8 then
        return 1, 0, 0
    elseif age >= 8 and age < 16 then
        return 2, 50, 200
    elseif age >=16 and age < 18 then
        return 3, 100, 400
    end
    return 0, -1, -1
end

---检测充值限制
function LxCopyrightCtrl:CheckRecharge(payData)
    local age = self._realNameAge or 0
    local ageType, oneLimit, totalLimit = self:GetAgeRechargeLimit(age)
    if ageType > 0 then
        local limitType = 0
        local val = payData.payValue
        if ageType == 1 then
            limitType = 1
        elseif val > oneLimit then
            limitType = 1
        else
            local roleInfo = ModuleCenter.Role:GetRoleInfo()
            local totalVal = roleInfo and roleInfo.thirtyCharge or 0
            local nextVal = totalVal + val
            if nextVal > totalLimit then
                limitType = 2
            end
        end
        if limitType > 0 then
            ShowPanel(UiNames.AntiPay, {ageType = ageType, limitType = limitType})
            return false
        end
    end
    return true
end

---检测在线时长
function LxCopyrightCtrl:StartCheckOnlineTime()
    if self:FindTimer(TIMER_ID.online) then
        return
    end
    self._startCheckTime = LxUtil.OSTime()
    self:StartTimer(TIMER_ID.online, 1, false, -1, function()
        self:CheckOnlineTime()
    end)
end

function LxCopyrightCtrl:CheckOnlineTime()
    if not self:CheckYoungHoliday() then
        self:StopTimer(TIMER_ID.online)
    end
end

---检测当前时间
function LxCopyrightCtrl:CheckValidDate()
    if self._realNameAge >= 18 then
        return true
    end
    local sDate = LxUtil.OSDate("*t", LxUtil.OSTime())
    local year, month, day = sDate.year, sDate.month, sDate.day
    local key = string.format("%d-%02d-%02d",year, month, day)
    if not self._holiday[key] then
       return false
    end
    local hour = sDate.hour
    if hour < 20 or hour >= 21 then
        return false
    end
    return true
end

---检测实名认证
function LxCopyrightCtrl:CheckRealName(userName)
    if not self._isRealName then
        ShowPanel(UiNames.AuthID, {userName=userName})
        return false
    end
    return true
end

---充值UI
function LxCopyrightCtrl:OpenRechargeUI(payData, callback)
    if not self:CheckRecharge(payData) then
        return
    end
    ShowPanel(UiNames.FakePay, {payData = payData, callback=callback})
end

function LxCopyrightCtrl:CheckYoungHoliday()
    if self._realNameAge >= 18 then
        return true
    end
    if self:CheckValidDate() then
        return true
    end
    ShowPanel(UiNames.AntiAlert)
    return false
end


return LxCopyrightCtrl